import zeep
from zeep import Client
from zeep.transports import Transport
from requests import Session
import sys

def create_soap_client(wsdl_url):
    session = Session()
    transport = Transport(session=session)
    client = Client(wsdl_url, transport=transport)
    return client

def lookup_policy_direct_xml(wsdl_url, policy_number, customer_name):
    session = Session()
    transport = Transport(session=session)
    client = Client(wsdl_url, transport=transport)
    
    soap_body = f"""
    <soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:ins="http://insurance.example.com/">
       <soapenv:Header/>
       <soapenv:Body>
          <ins:PolicyLookup>
             <ins:PolicyNumber>{policy_number}</ins:PolicyNumber>
             <ins:CustomerName>{customer_name}</ins:CustomerName>
          </ins:PolicyLookup>
       </soapenv:Body>
    </soapenv:Envelope>
    """
    
    response = session.post(
        client.service._binding_options['address'],
        data=soap_body,
        headers={'Content-Type': 'text/xml; charset=utf-8'}
    )
    
    return response.text

def lookup_policy_zeep(wsdl_url, policy_number, customer_name):
    client = create_soap_client(wsdl_url)
    
    result = client.service.PolicyLookup(
        PolicyNumber=policy_number,
        CustomerName=customer_name
    )
    
    return result

def get_quote_direct_xml(wsdl_url, policy_number, customer_name, coverage_type):
    session = Session()
