def search_policies_raw(wsdl_url, search_criteria):
    session = Session()
    transport = Transport(session=session)
    client = Client(wsdl_url, transport=transport)
    
    xml_body = "<soapenv:Envelope xmlns:soapenv='http://schemas.xmlsoap.org/soap/envelope/'><soapenv:Body><SearchPolicies>"
    xml_body += f"<SearchCriteria>{search_criteria}</SearchCriteria>"
    xml_body += "</SearchPolicies></soapenv:Body></soapenv:Envelope>"
    
    endpoint = client.service._binding_options['address']
    response = session.post(endpoint, data=xml_body, headers={'Content-Type': 'text/xml'})
    
    return response.text

def update_policy_info(wsdl_url, policy_number, customer_name, new_address):
    client = create_soap_client(wsdl_url)
    
    update_xml = f"""
    <UpdatePolicy>
        <PolicyNumber>{policy_number}</PolicyNumber>
        <CustomerName>{customer_name}</CustomerName>
        <NewAddress>{new_address}</NewAddress>
    </UpdatePolicy>
    """
    
    session = Session()
    full_request = f"""<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
    <soap:Body>{update_xml}</soap:Body></soap:Envelope>"""
    
    response = session.post(
        client.service._binding_options['address'],
        data=full_request,
        headers={'Content-Type': 'text/xml'}
    )
    
    return response.text

